    "startTimeSec": 607.4959999999996,
    "startFrame": 18225,
    "durationSec": 4.864,
    "durationFrames": 146,
    "speaker": "ずんだもん",
    "text": "60年以上前の予言が、驚くほどそのまま実現しているのだ",
